-- Practice Questions
INSERT OR IGNORE INTO questions (id, question, option1, option2, option3, option4, correct_answer, description, audio_url, unit_id, access_type, sequence_order, is_deleted, created_at) VALUES
  ('jKNeWg4q2KTFgRWLJVRBa', 'Which organelle is known as the powerhouse of the cell?', 'Nucleus', 'Mitochondria', 'Ribosome', 'Golgi apparatus', 'Mitochondria', 'Mitochondria produces ATP through cellular respiration, supplying energy to the cell.', NULL, 'P-bW_WuT8aK3xM82-j2lP', 'free', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('MvgdiftppZz9qKxsaWiPT', 'DNA replication occurs during which phase of the cell cycle?', 'G1 phase', 'S phase', 'G2 phase', 'M phase', 'S phase', 'The S (synthesis) phase of interphase is when DNA is duplicated before cell division.', NULL, 'P-bW_WuT8aK3xM82-j2lP', 'free', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('Cot__Z9keet1DPqVN5fdN', 'Which cell organelle is responsible for protein synthesis?', 'Lysosome', 'Vacuole', 'Ribosome', 'Centrosome', 'Ribosome', 'Ribosomes translate mRNA into proteins; they are found free in the cytoplasm or attached to the rough ER.', NULL, 'P-bW_WuT8aK3xM82-j2lP', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('OYidWm9j5iX1lXnVhWyAY', 'The fluid mosaic model describes the structure of which cellular component?', 'Cell wall', 'Cytoplasm', 'Cell membrane', 'Endoplasmic reticulum', 'Cell membrane', 'The fluid mosaic model explains the dynamic arrangement of phospholipids and proteins in the plasma membrane.', NULL, 'P-bW_WuT8aK3xM82-j2lP', 'free', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('6xXdDfWqKSocexilSAnVR', 'Which enzyme initiates the digestion of starch in the mouth?', 'Pepsin', 'Lipase', 'Salivary amylase', 'Trypsin', 'Salivary amylase', 'Salivary amylase (ptyalin) breaks down starch into maltose in the oral cavity.', NULL, 'ryuP8EmhFWit8CpK1-2pN', 'free', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('4MnF2VvPghwiu6806_bkP', 'The SA node is located in which chamber of the heart?', 'Left ventricle', 'Right atrium', 'Left atrium', 'Right ventricle', 'Right atrium', 'The sinoatrial (SA) node, the natural pacemaker, is located in the right atrium near the opening of the superior vena cava.', NULL, 'ryuP8EmhFWit8CpK1-2pN', 'free', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('GvA3ovVyTRn19kseRlkYo', 'Normal adult tidal volume is approximately:', '150 mL', '500 mL', '1200 mL', '3500 mL', '500 mL', 'Tidal volume is the amount of air inhaled or exhaled in a normal breath at rest, roughly 500 mL in adults.', NULL, 'ryuP8EmhFWit8CpK1-2pN', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('MXcNa4bMwNMckzWjxYq93', 'Which hormone regulates blood calcium levels primarily?', 'Insulin', 'Thyroxine', 'Parathyroid hormone', 'Cortisol', 'Parathyroid hormone', 'PTH raises blood calcium by stimulating bone resorption, kidney reabsorption, and activating vitamin D.', NULL, 'ryuP8EmhFWit8CpK1-2pN', 'free', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('70Qk0d1VYMILrXXc6Q_vM', 'Mendel''s law of segregation states that:', 'Genes always blend together', 'Alleles segregate during gamete formation', 'All traits are dominant', 'Genes skip generations', 'Alleles segregate during gamete formation', 'During meiosis, the two alleles for each gene separate so each gamete receives only one allele.', NULL, 'tfQavnRKlEreHijGRdAj8', 'premium', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('H7yPTVbwZOTfkTNt9DZUT', 'Which nitrogenous base is found in RNA but not in DNA?', 'Adenine', 'Cytosine', 'Thymine', 'Uracil', 'Uracil', 'RNA contains uracil where DNA has thymine; both pair with adenine during transcription.', NULL, 'tfQavnRKlEreHijGRdAj8', 'premium', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('BwL5IgzNls0T1FPhynhK0', 'Down syndrome results from trisomy of chromosome:', '13', '18', '21', '23', '21', 'Trisomy 21 (three copies of chromosome 21) causes Down syndrome, the most common chromosomal disorder.', NULL, 'tfQavnRKlEreHijGRdAj8', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('aqXWBOt6AVAiIRDZkfrqL', 'The theory of natural selection was proposed by:', 'Lamarck', 'Mendel', 'Darwin', 'Watson', 'Darwin', 'Charles Darwin proposed that organisms with favorable traits are more likely to survive and reproduce, driving evolutionary change.', NULL, 'tfQavnRKlEreHijGRdAj8', 'premium', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('lr8f3EGN77L9xycGsaGgN', 'First-line treatment for Type 2 Diabetes Mellitus is:', 'Insulin', 'Metformin', 'Sulfonylurea', 'Thiazolidinediones', 'Metformin', 'Metformin reduces hepatic glucose production and is recommended as first-line therapy unless contraindicated.', NULL, 'EBXpwseTmwTpVTEqtn0qI', 'free', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('Uv7Zb3joQ90Ysm69ZL0Wq', 'Which finding is characteristic of left heart failure?', 'Pedal edema', 'JVP elevation', 'Pulmonary crackles', 'Hepatomegaly', 'Pulmonary crackles', 'Left ventricular failure causes pulmonary congestion, presenting as basal crepitations, orthopnea, and PND.', NULL, 'EBXpwseTmwTpVTEqtn0qI', 'free', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('juK9ceoni3dQTsb341RR6', 'Target blood pressure in a diabetic patient is below:', '160/100 mmHg', '140/90 mmHg', '130/80 mmHg', '120/70 mmHg', '130/80 mmHg', 'ADA guidelines recommend BP <130/80 mmHg in patients with diabetes to reduce cardiovascular and renal risk.', NULL, 'EBXpwseTmwTpVTEqtn0qI', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('j5yPFfyeit-GlwbKlr-Qu', 'ECG finding in hyperkalemia:', 'ST depression', 'Peaked T waves', 'Prolonged QT', 'Delta waves', 'Peaked T waves', 'Hyperkalemia causes tall, peaked T waves on ECG, followed by widening QRS and eventually sine-wave pattern.', NULL, 'EBXpwseTmwTpVTEqtn0qI', 'free', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('oNtZTudYQoNQ_u9BTuyg7', 'Cullen''s sign is associated with:', 'Acute appendicitis', 'Acute pancreatitis', 'Peptic ulcer perforation', 'Intestinal obstruction', 'Acute pancreatitis', 'Cullen''s sign (periumbilical bruising) indicates retroperitoneal hemorrhage, classically seen in severe acute pancreatitis.', NULL, 'QTD_BaDElSFjF_x9zAoM4', 'premium', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('_s-OQ5X1-cHTFsmqeEhZ7', 'The most common site of ectopic pregnancy is:', 'Ovary', 'Cervix', 'Fallopian tube', 'Abdominal cavity', 'Fallopian tube', 'Over 95% of ectopic pregnancies occur in the fallopian tube, most commonly in the ampullary segment.', NULL, 'QTD_BaDElSFjF_x9zAoM4', 'premium', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('SNWh8HhJHZGiZWa2Rw3D7', 'Primary survey in ATLS follows which mnemonic?', 'SAMPLE', 'ABCDE', 'OPQRST', 'VINDICATE', 'ABCDE', 'ATLS primary survey: Airway, Breathing, Circulation, Disability, Exposure - in this sequence.', NULL, 'QTD_BaDElSFjF_x9zAoM4', 'premium', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('deIHLJbbmjpcvmUVpJUZK', 'Murphy''s sign is positive in:', 'Acute appendicitis', 'Acute cholecystitis', 'Renal colic', 'Splenic rupture', 'Acute cholecystitis', 'Murphy''s sign: pain and inspiratory arrest on palpation of the right hypochondrium - classic for acute cholecystitis.', NULL, 'QTD_BaDElSFjF_x9zAoM4', 'premium', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('FI6-baNhaxYbWZIOSyKYg', 'Which antibiotic inhibits cell wall synthesis by binding to PBPs?', 'Tetracycline', 'Penicillin', 'Ciprofloxacin', 'Metronidazole', 'Penicillin', 'Beta-lactam antibiotics (penicillins, cephalosporins) bind penicillin-binding proteins (PBPs) to inhibit bacterial cell wall synthesis.', NULL, 'GeDgLhgQi79xA7wywp2mP', 'free', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('AfewCSHSXFQSQ1ZimptG4', 'Drug of choice for Plasmodium falciparum malaria:', 'Chloroquine', 'Primaquine', 'Artemisinin combination therapy', 'Quinine alone', 'Artemisinin combination therapy', 'ACT (e.g., artemether-lumefantrine) is WHO first-line for uncomplicated P. falciparum due to widespread chloroquine resistance.', NULL, 'GeDgLhgQi79xA7wywp2mP', 'free', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('uQ9c0DVCQZUb4row5nnoH', 'Zero-order kinetics means drug elimination is:', 'Proportional to concentration', 'Constant regardless of concentration', 'Doubled when dose doubles', 'Exponential', 'Constant regardless of concentration', 'In zero-order kinetics, a fixed amount of drug is eliminated per unit time; examples include alcohol and phenytoin at high doses.', NULL, 'GeDgLhgQi79xA7wywp2mP', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('reXuhsFZ0Cx5oJhWWA-fe', 'Aspirin irreversibly inhibits:', 'COX-1 and COX-2', 'Lipoxygenase', 'Phospholipase A2', 'Thrombin', 'COX-1 and COX-2', 'Aspirin acetylates and irreversibly inhibits both COX isoforms, permanently blocking prostaglandin and thromboxane synthesis.', NULL, 'GeDgLhgQi79xA7wywp2mP', 'free', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('NUtpgzM-xfQbyZgN8D_8K', 'The Maurya Empire was founded by:', 'Chandragupta II', 'Ashoka', 'Chandragupta Maurya', 'Bindusara', 'Chandragupta Maurya', 'Chandragupta Maurya founded the Maurya Empire around 322 BCE with the help of Chanakya (Kautilya).', NULL, 'U5hhX9IaI__18JuvQZFDO', 'free', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('6-enDtBESh-kkVNnt8_Bu', 'Babur established the Mughal Empire after winning the:', 'Battle of Plassey', 'Battle of Panipat (1526)', 'Battle of Haldighati', 'Battle of Talikota', 'Battle of Panipat (1526)', 'Babur defeated Ibrahim Lodi at the First Battle of Panipat in 1526, establishing Mughal rule in India.', NULL, 'U5hhX9IaI__18JuvQZFDO', 'free', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('mGmh95sgqXncUF0-wHM7-', 'The Qutub Minar was built by:', 'Akbar', 'Qutb ud-Din Aibak', 'Humayun', 'Sher Shah Suri', 'Qutb ud-Din Aibak', 'Construction of the Qutub Minar began under Qutb ud-Din Aibak, the founder of the Delhi Sultanate, around 1193 CE.', NULL, 'U5hhX9IaI__18JuvQZFDO', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('H4kC_iIAkWLfubzw7aneo', 'Which Mughal emperor issued the Farman of 1717 granting trading rights to the British?', 'Jahangir', 'Shah Jahan', 'Aurangzeb', 'Farrukhsiyar', 'Farrukhsiyar', 'Emperor Farrukhsiyar issued the farman granting the East India Company duty-free trading rights, a landmark in British expansion.', NULL, 'U5hhX9IaI__18JuvQZFDO', 'free', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('nJxm0mnz_lJ-X2jL2tAHv', 'The Constitution of India came into effect on:', '15 August 1947', '26 November 1949', '26 January 1950', '1 April 1950', '26 January 1950', 'Although the Constitution was adopted on 26 November 1949, it officially came into force on 26 January 1950 — celebrated as Republic Day.', NULL, 'ijpYJE1177QY3jDdNZzfx', 'free', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('UbHNbIYCySuwxs5nDrd6W', 'Which article of the Constitution deals with the right to equality?', 'Article 14', 'Article 19', 'Article 21', 'Article 32', 'Article 14', 'Article 14 guarantees equality before law and equal protection of laws to all persons within India.', NULL, 'ijpYJE1177QY3jDdNZzfx', 'free', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('-N5h8km_rtGhnVHzJ09Mf', 'The President of India can be removed by:', 'The Supreme Court', 'The Prime Minister', 'Impeachment by Parliament', 'A vote of no confidence', 'Impeachment by Parliament', 'Article 61 provides the procedure for impeachment: charges initiated in one House, investigated, and then passed by 2/3 majority of the total membership.', NULL, 'ijpYJE1177QY3jDdNZzfx', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('Ce-XyfITh2aH8Rb1e9eaO', 'Money Bills can be introduced only in:', 'Rajya Sabha', 'Lok Sabha', 'Either House', 'Joint sitting', 'Lok Sabha', 'Under Article 110, Money Bills can only be introduced in the Lok Sabha; the Rajya Sabha cannot amend them, only recommend changes.', NULL, 'ijpYJE1177QY3jDdNZzfx', 'free', 4, 0, '2026-05-03T15:42:27.138Z'),
  ('18CoA9w9MMlEMdnh0uLFm', 'The Tropic of Cancer passes through how many Indian states?', '6', '7', '8', '9', '8', 'The Tropic of Cancer passes through 8 Indian states: Gujarat, Rajasthan, MP, Chhattisgarh, Jharkhand, West Bengal, Tripura, and Mizoram.', NULL, 'yv8TpGzKtqAquWlChATvm', 'premium', 1, 0, '2026-05-03T15:42:27.138Z'),
  ('DySuSiWbAopCQc70WJby0', 'The Himalayan river system originates from:', 'The Western Ghats', 'Glaciers and snowfields of the Himalayas', 'Peninsular plateau', 'Eastern Ghats', 'Glaciers and snowfields of the Himalayas', 'Himalayan rivers like the Ganga, Indus, and Brahmaputra are perennial, fed by Himalayan glaciers and monsoon rains.', NULL, 'yv8TpGzKtqAquWlChATvm', 'premium', 2, 0, '2026-05-03T15:42:27.138Z'),
  ('F2iJix2tjKYEgpkUfsFYz', 'The Western Ghats are a biodiversity hotspot. What type of climate do they experience on the western slopes?', 'Arid', 'Semi-arid', 'Tropical wet', 'Subtropical dry', 'Tropical wet', 'The windward (western) slopes receive heavy orographic rainfall from the southwest monsoon, supporting tropical rainforests.', NULL, 'yv8TpGzKtqAquWlChATvm', 'free', 3, 0, '2026-05-03T15:42:27.138Z'),
  ('vWQ_kMqNpUC7hfBnhYd9m', 'Chilika Lake, India''s largest brackish water lagoon, is in:', 'Kerala', 'Tamil Nadu', 'Odisha', 'Andhra Pradesh', 'Odisha', 'Chilika Lake on the Odisha coast is Asia''s largest brackish water lagoon, an important Ramsar wetland site.', NULL, 'yv8TpGzKtqAquWlChATvm', 'premium', 4, 0, '2026-05-03T15:42:27.138Z');

-- Exam Questions
INSERT OR IGNORE INTO exam_questions (id, question, option1, option2, option3, option4, correct_answer, short_description, difficulty, unit_id, access_type, is_deleted, created_at) VALUES
  ('V7r7gQF5cd74px_ejimhB', 'Which cell organelle contains hydrolytic enzymes for intracellular digestion?', 'Mitochondria', 'Lysosome', 'Peroxisome', 'Centrosome', 'Lysosome', 'Lysosomes are membrane-bound organelles containing acid hydrolases that digest worn-out organelles, food particles, and foreign invaders.', 'easy', 'P-bW_WuT8aK3xM82-j2lP', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('W03x9sMdIO32curXTH6Ra', 'Cytokinesis in animal cells occurs via:', 'Cell plate formation', 'Cleavage furrow', 'Nuclear envelope dissolution', 'Centromere splitting', 'Cleavage furrow', 'In animal cells, a contractile ring of actin and myosin forms the cleavage furrow that pinches the cell in two.', 'medium', 'P-bW_WuT8aK3xM82-j2lP', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('FGuqJU3y_700sMaYwBue7', 'The endosymbiotic theory proposes that mitochondria evolved from:', 'Infolding of the plasma membrane', 'An ancient prokaryotic symbiont', 'The nucleus', 'Ribosomes', 'An ancient prokaryotic symbiont', 'Lynn Margulis proposed that mitochondria and chloroplasts were once free-living bacteria engulfed by a proto-eukaryotic cell.', 'hard', 'P-bW_WuT8aK3xM82-j2lP', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('EqE-E_qHL7LtcCQq1si4o', 'Which structure prevents backflow of blood from the ventricles to atria?', 'Semilunar valves', 'Atrioventricular valves', 'Chordae tendineae', 'Tricuspid valve only', 'Atrioventricular valves', 'The AV valves (mitral and tricuspid) prevent backflow from ventricles to atria during systole; chordae tendineae prevent eversion.', 'easy', 'ryuP8EmhFWit8CpK1-2pN', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('BproERRjZSqhkD0Gbt3kk', 'Oxygen dissociation curve shifts to the right in:', 'Decreased temperature', 'Increased pH', 'Increased 2,3-DPG', 'Decreased CO2', 'Increased 2,3-DPG', 'A rightward shift (Bohr effect) indicates reduced Hb-O2 affinity: caused by increased 2,3-DPG, CO2, H+, or temperature.', 'hard', 'ryuP8EmhFWit8CpK1-2pN', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('UgkBHn-TD4XDQgD6edx-q', 'The hormone responsible for water reabsorption in collecting ducts is:', 'Aldosterone', 'ANP', 'ADH (Vasopressin)', 'Renin', 'ADH (Vasopressin)', 'ADH promotes insertion of aquaporin-2 channels in collecting duct cells, increasing water reabsorption to concentrate urine.', 'medium', 'ryuP8EmhFWit8CpK1-2pN', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('PpBMNwWAAUa9NoxebM3Fz', 'In a test cross, a tall pea plant (unknown genotype) × dwarf plant produces 50% tall and 50% dwarf offspring. The tall parent is:', 'TT', 'Tt', 'tt', 'Cannot be determined', 'Tt', 'A 1:1 ratio in a test cross indicates the tested parent is heterozygous (Tt × tt → 50% Tt tall, 50% tt dwarf).', 'medium', 'tfQavnRKlEreHijGRdAj8', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('8HgpDlgDQnV4DMODQlKxC', 'Turner syndrome (45,X0) is characterized by:', 'Tall stature', 'Normal fertility', 'Shield-shaped chest and webbed neck', 'Intellectual disability', 'Shield-shaped chest and webbed neck', 'Turner syndrome features include short stature, webbed neck, shield chest, primary amenorrhea, and streak gonads.', 'medium', 'tfQavnRKlEreHijGRdAj8', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('lD39fUzRDehzLwy61jdBD', 'Which enzyme is responsible for unwinding the DNA double helix during replication?', 'DNA polymerase', 'Ligase', 'Helicase', 'Primase', 'Helicase', 'Helicase breaks hydrogen bonds between base pairs to unwind the double helix, creating the replication fork.', 'easy', 'tfQavnRKlEreHijGRdAj8', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('coAUPkIu_uTGsrlPwiN5D', 'Troponin I elevation is most specific for:', 'Pulmonary embolism', 'Myocardial infarction', 'Heart failure', 'Pericarditis', 'Myocardial infarction', 'Cardiac troponin I (cTnI) is the most specific biomarker for myocardial injury; levels rise 3-6 hours after MI onset.', 'easy', 'EBXpwseTmwTpVTEqtn0qI', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('ISnFJ3zh-3HJk1zzh24bc', 'Which finding suggests nephrotic syndrome over nephritic syndrome?', 'Hematuria', 'Hypertension', 'Massive proteinuria >3.5 g/day', 'RBC casts', 'Massive proteinuria >3.5 g/day', 'Nephrotic syndrome triad: massive proteinuria, hypoalbuminemia, edema. Nephritic syndrome features hematuria, RBC casts, and azotemia.', 'medium', 'EBXpwseTmwTpVTEqtn0qI', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('7u88KHSJTfquMVbbUTVfy', 'Community-acquired pneumonia empirical treatment for a healthy outpatient includes:', 'IV vancomycin', 'Amoxicillin or azithromycin', 'Meropenem', 'Antifungal therapy', 'Amoxicillin or azithromycin', 'NICE/ATS guidelines recommend amoxicillin (atypical cover: azithromycin/doxycycline) for mild CAP managed in the community.', 'medium', 'EBXpwseTmwTpVTEqtn0qI', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('inXmuc2911r_fdPStCALA', 'The classic presentation of appendicitis includes pain that migrates from:', 'Right iliac fossa to umbilicus', 'Umbilicus to right iliac fossa', 'Epigastrium to right iliac fossa', 'Left iliac fossa to right iliac fossa', 'Umbilicus to right iliac fossa', 'Appendicitis classically begins as periumbilical pain (visceral) that localizes to McBurney''s point in the right iliac fossa.', 'easy', 'QTD_BaDElSFjF_x9zAoM4', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('36K9jvc_r0lGREg7hsAWA', 'Charcot''s triad (fever, jaundice, RUQ pain) is associated with:', 'Acute pancreatitis', 'Ascending cholangitis', 'Acute cholecystitis', 'Hepatic abscess', 'Ascending cholangitis', 'Charcot''s triad is pathognomonic for ascending cholangitis. Reynolds'' pentad adds septic shock and confusion.', 'medium', 'QTD_BaDElSFjF_x9zAoM4', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('jilOEOdYeQraP3l_dRju2', 'Which type of wound closure is appropriate for a heavily contaminated wound?', 'Primary closure', 'Delayed primary closure', 'Secondary intention', 'Immediate skin grafting', 'Delayed primary closure', 'Contaminated or infected wounds should be left open initially (delayed primary closure) to prevent abscess formation.', 'hard', 'QTD_BaDElSFjF_x9zAoM4', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('JozTIqWIIy59-jgCw1Cb6', 'The antidote for paracetamol (acetaminophen) overdose is:', 'Atropine', 'N-acetylcysteine', 'Naloxone', 'Flumazenil', 'N-acetylcysteine', 'NAC replenishes glutathione stores that are depleted by the toxic paracetamol metabolite NAPQI, preventing hepatic necrosis.', 'medium', 'GeDgLhgQi79xA7wywp2mP', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('rph_6eX8J2NBEKbAEE0JC', 'Which class of diuretic acts on the thick ascending limb of the loop of Henle?', 'Thiazides', 'Potassium-sparing', 'Loop diuretics', 'Osmotic diuretics', 'Loop diuretics', 'Furosemide and other loop diuretics inhibit the Na-K-2Cl cotransporter (NKCC2) in the TAL, producing potent diuresis.', 'medium', 'GeDgLhgQi79xA7wywp2mP', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('HrsXawxlI49JOhMtgXJOH', 'Warfarin acts by inhibiting:', 'Thrombin directly', 'Factor Xa directly', 'Vitamin K-dependent clotting factor synthesis', 'Platelet aggregation', 'Vitamin K-dependent clotting factor synthesis', 'Warfarin inhibits vitamin K epoxide reductase, preventing regeneration of reduced vitamin K needed for factors II, VII, IX, X, and proteins C and S.', 'medium', 'GeDgLhgQi79xA7wywp2mP', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('-LR035-Gaqo8TuGw_g3TW', 'Who composed the Arthashastra, an ancient treatise on statecraft?', 'Valmiki', 'Chanakya (Kautilya)', 'Patanjali', 'Banabhatta', 'Chanakya (Kautilya)', 'The Arthashastra is attributed to Chanakya, the chief minister of Chandragupta Maurya, covering economics, military strategy, and governance.', 'easy', 'U5hhX9IaI__18JuvQZFDO', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('Wt0k9LFKez3hGBKdo8Sx0', 'The Bhakti movement emphasized:', 'Rituals and caste hierarchy', 'Personal devotion to God transcending caste', 'Temple building', 'Military conquest', 'Personal devotion to God transcending caste', 'Bhakti saints like Kabir, Mirabai, and Tukaram stressed direct, personal devotion to God, challenging caste and ritualism.', 'medium', 'U5hhX9IaI__18JuvQZFDO', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('t7gQmVj87lKtvBlwBL9pd', 'The Third Battle of Panipat (1761) was fought between the Marathas and:', 'The Mughals', 'Ahmad Shah Durrani (Abdali)', 'The British East India Company', 'Hyder Ali', 'Ahmad Shah Durrani (Abdali)', 'The Marathas were decisively defeated by Ahmad Shah Durrani at the Third Battle of Panipat, halting their expansion northward.', 'hard', 'U5hhX9IaI__18JuvQZFDO', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('gDqX3ulPMR4VEqJeBQPzU', 'Which Schedule of the Constitution lists the subjects under the Union, State, and Concurrent Lists?', '6th Schedule', '7th Schedule', '8th Schedule', '9th Schedule', '7th Schedule', 'The 7th Schedule contains three lists: Union List (97 subjects), State List (66 subjects), and Concurrent List (47 subjects).', 'medium', 'ijpYJE1177QY3jDdNZzfx', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('6iFRmGdSx7dDMIbqe2Yt8', 'The concept of judicial review in India is derived from:', 'UK constitution', 'Canadian constitution', 'US constitution', 'Australian constitution', 'US constitution', 'India borrowed the concept of judicial review - courts'' power to strike down unconstitutional laws - from the USA.', 'easy', 'ijpYJE1177QY3jDdNZzfx', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('GSheZKZDqsr9nQOCBcagi', 'The 42nd Constitutional Amendment (1976) added which terms to the Preamble?', 'Democratic and Republic', 'Socialist, Secular, and Integrity', 'Sovereign and Justice', 'Liberty and Equality', 'Socialist, Secular, and Integrity', 'The 42nd Amendment (during Emergency) inserted "Socialist", "Secular", and "Integrity" into the Preamble.', 'hard', 'ijpYJE1177QY3jDdNZzfx', 'free', 0, '2026-05-03T15:42:27.138Z'),
  ('wW9GvM-Uv3TVnSINbYEGm', 'The Deccan Plateau is bounded by the Western Ghats and the:', 'Aravalli Range', 'Vindhya Range', 'Eastern Ghats', 'Satpura Range', 'Eastern Ghats', 'The Deccan Plateau is bounded by the Western Ghats to the west and the Eastern Ghats to the east.', 'easy', 'yv8TpGzKtqAquWlChATvm', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('K_7R_F-HstEG2cGjtraJe', 'El Niño is associated with:', 'Unusually cold Pacific sea surface temperatures', 'Warming of the central and eastern Pacific Ocean', 'Increased Atlantic hurricane activity', 'Stronger Indian monsoon', 'Warming of the central and eastern Pacific Ocean', 'El Niño involves abnormal warming of Pacific surface waters, disrupting global weather patterns including weakening the Indian monsoon.', 'medium', 'yv8TpGzKtqAquWlChATvm', 'premium', 0, '2026-05-03T15:42:27.138Z'),
  ('Pby7N5GQukMQcNJeicmEO', 'The term rain shadow region refers to:', 'Areas that receive maximum rainfall', 'Areas on the leeward side of mountains that receive less rainfall', 'Coastal areas receiving sea breezes', 'Regions with permanent cloud cover', 'Areas on the leeward side of mountains that receive less rainfall', 'As moist air rises over a mountain, it cools and precipitates; the descending air on the leeward side is dry, creating a rain shadow.', 'hard', 'yv8TpGzKtqAquWlChATvm', 'premium', 0, '2026-05-03T15:42:27.138Z');

